module gray_counter #(
    parameter integer WIDTH = 4,
    parameter integer CLOCK_FREQ_MHZ = 200
) (
    input  logic             clk,
    input  logic             rst_n,
    input  logic             enable,
    input  logic             clear,
    output logic [WIDTH-1:0] gray_value,
    output logic [WIDTH-1:0] bin_value,
    output logic             done
);

    // Keep SSOT top-level timing parameter as a first-class top contract knob.
    // The core currently consumes WIDTH only; this reference prevents an unused-parameter lint diagnostic.
    localparam integer CLOCK_FREQ_MHZ_CFG = CLOCK_FREQ_MHZ;

    gray_counter_core #(
        .WIDTH(WIDTH)
    ) u_gray_counter_core (
        .clk       (clk),
        .rst_n     (rst_n),
        .enable    (enable),
        .clear     (clear),
        .gray_value(gray_value),
        .bin_value (bin_value),
        .done      (done)
    );

endmodule

